import{_ as s,o as t,c as a,ag as i}from"./chunks/framework.B_-t2C-M.js";const u=JSON.parse('{"title":"Testing & Quality Assurance","description":"","frontmatter":{},"headers":[],"relativePath":"guide/testing.md","filePath":"guide/testing.md"}'),n={name:"guide/testing.md"};function r(o,e,l,c,d,p){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="testing-quality-assurance" tabindex="-1">Testing &amp; Quality Assurance <a class="header-anchor" href="#testing-quality-assurance" aria-label="Permalink to &quot;Testing &amp; Quality Assurance&quot;">​</a></h1><p>LaraCommerce ships with an incredibly robust test suite designed to guarantee application stability. The project achieves <strong>100% code coverage</strong> across all classes — Controllers, Services, Models, Middleware, Requests, Resources, Observers, Policies, Notifications, Enums, and Traits.</p><hr><h2 id="test-infrastructure" tabindex="-1">Test Infrastructure <a class="header-anchor" href="#test-infrastructure" aria-label="Permalink to &quot;Test Infrastructure&quot;">​</a></h2><p>We use <strong>PHPUnit</strong> natively integrated with Laravel&#39;s testing framework.</p><h3 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h3><p>The test environment (<code>APP_ENV=testing</code>) is optimized for speed:</p><ul><li><strong>Database</strong>: Uses an <strong>in-memory SQLite</strong> database (<code>:memory:</code>). This means tests run extremely fast without writing to disk or requiring a dedicated test MySQL server.</li><li><strong>Cache &amp; Session</strong>: Uses the <code>array</code> driver (wiped clean after every test).</li><li><strong>Queue</strong>: Uses the <code>sync</code> connection to execute jobs immediately during tests.</li><li><strong>Search</strong>: Uses the <code>collection</code> driver for Laravel Scout, mocking Meilisearch.</li></ul><h3 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tests/</span></span>
<span class="line"><span>├── Feature/</span></span>
<span class="line"><span>│   ├── Api/</span></span>
<span class="line"><span>│   │   ├── Admin/         # Admin endpoints (Products, Orders, Refunds, Shipments...)</span></span>
<span class="line"><span>│   │   ├── Auth/          # Login, Register, Password Reset, Social Auth, Tokens</span></span>
<span class="line"><span>│   │   ├── Cart/          # Cart logic, coupons</span></span>
<span class="line"><span>│   │   ├── Catalogue/     # Browsing, Search, Collections, Currencies</span></span>
<span class="line"><span>│   │   ├── Content/       # Blog, Pages</span></span>
<span class="line"><span>│   │   ├── Marketing/     # Affiliates, Loyalty, Gift Cards, Newsletters</span></span>
<span class="line"><span>│   │   ├── Orders/        # Checkout, Cancel, Returns</span></span>
<span class="line"><span>│   │   ├── Payments/      # Payment intents, webhooks</span></span>
<span class="line"><span>│   │   └── User/          # Profile, Addresses, Wallet, Payment Methods</span></span>
<span class="line"><span>│   ├── Policies/          # Authorization policy tests</span></span>
<span class="line"><span>│   └── Webhooks/          # Stripe webhook simulation</span></span>
<span class="line"><span>├── Unit/</span></span>
<span class="line"><span>│   ├── Coverage/          # Remaining coverage gap tests</span></span>
<span class="line"><span>│   ├── Enums/             # Enum value and label tests</span></span>
<span class="line"><span>│   ├── Events/            # Event dispatch tests</span></span>
<span class="line"><span>│   ├── Exceptions/        # Exception formatting tests</span></span>
<span class="line"><span>│   ├── Jobs/              # Queue job tests</span></span>
<span class="line"><span>│   ├── Middleware/         # Middleware behavior tests</span></span>
<span class="line"><span>│   ├── Models/            # Model relations, accessors, scopes</span></span>
<span class="line"><span>│   ├── Notifications/     # Notification content and channel tests</span></span>
<span class="line"><span>│   ├── Observers/         # Observer side-effect tests</span></span>
<span class="line"><span>│   ├── Requests/          # Form request validation rules</span></span>
<span class="line"><span>│   ├── Resources/         # API resource transformation tests</span></span>
<span class="line"><span>│   ├── Services/          # Business logic (Order, Payment, Refund, Wallet...)</span></span>
<span class="line"><span>│   └── Traits/            # Trait behavior tests</span></span>
<span class="line"><span>└── TestCase.php           # Base test configuration</span></span></code></pre></div><hr><h2 id="code-coverage" tabindex="-1">Code Coverage <a class="header-anchor" href="#code-coverage" aria-label="Permalink to &quot;Code Coverage&quot;">​</a></h2><p>LaraCommerce achieves <strong>100% line coverage</strong> on the entire <code>app/</code> directory.</p><table tabindex="0"><thead><tr><th>Layer</th><th>Coverage</th></tr></thead><tbody><tr><td>Controllers (55+)</td><td>100%</td></tr><tr><td>Services (25+)</td><td>100%</td></tr><tr><td>Models (50+)</td><td>100%</td></tr><tr><td>Middleware (6)</td><td>100%</td></tr><tr><td>Form Requests (60+)</td><td>100%</td></tr><tr><td>API Resources (60+)</td><td>100%</td></tr><tr><td>Observers (8)</td><td>100%</td></tr><tr><td>Policies (18)</td><td>100%</td></tr><tr><td>Notifications (18)</td><td>100%</td></tr><tr><td>Enums (16)</td><td>100%</td></tr><tr><td>Traits (8)</td><td>100%</td></tr><tr><td>Jobs (8)</td><td>100%</td></tr><tr><td>Events (5)</td><td>100%</td></tr><tr><td>Exceptions (6)</td><td>100%</td></tr></tbody></table><p>To generate a coverage report:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --coverage</span></span></code></pre></div><p>For an HTML report:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdebug.mode=coverage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor/bin/phpunit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --coverage-html=coverage-report</span></span></code></pre></div><hr><h2 id="test-categories" tabindex="-1">Test Categories <a class="header-anchor" href="#test-categories" aria-label="Permalink to &quot;Test Categories&quot;">​</a></h2><h3 id="feature-tests-api-integration" tabindex="-1">Feature Tests (API Integration) <a class="header-anchor" href="#feature-tests-api-integration" aria-label="Permalink to &quot;Feature Tests (API Integration)&quot;">​</a></h3><p>The vast majority of the suite consists of Feature tests. These tests boot the Laravel application, make an HTTP request to an API endpoint, and assert the response status, JSON structure, and database changes.</p><p><strong>What we test:</strong></p><ul><li><strong>Status Codes</strong>: Ensuring <code>200</code>, <code>201</code>, <code>403</code>, <code>404</code>, and <code>422</code> are returned correctly.</li><li><strong>Authentication</strong>: Verifying that protected routes reject guests and unauthorized roles.</li><li><strong>Validation</strong>: Testing that missing or invalid payload data returns the exact expected validation errors.</li><li><strong>Cascading Deletes</strong>: We have a dedicated <code>DeletionCascadeTest</code> to ensure that deleting a user or a product cleanly removes all associated data (addresses, cart items, images) without leaving orphans in the database.</li><li><strong>Webhook Handlers</strong>: Full coverage of all 6 Stripe webhook event types (<code>payment_intent.succeeded</code>, <code>payment_failed</code>, <code>requires_action</code>, <code>charge.refunded</code>, <code>charge.dispute.created</code>, <code>refund.updated</code>) with real DB data.</li><li><strong>Policy Tests</strong>: Every authorization policy tested for owner, non-owner, and admin access patterns.</li></ul><h3 id="unit-tests" tabindex="-1">Unit Tests <a class="header-anchor" href="#unit-tests" aria-label="Permalink to &quot;Unit Tests&quot;">​</a></h3><p>Unit tests focus on isolated business logic within <code>app/Services/</code>.</p><ul><li><strong>OrderService</strong>: Checkout flow, stock deduction, tax calculation, status transitions, cancellation.</li><li><strong>PaymentService</strong>: Stripe intent creation with/without saved cards, payment confirmation (success &amp; failure branches), all 6 webhook handlers with real DB state, deduplication, idempotent shipment creation.</li><li><strong>RefundService</strong>: Refund to original payment (Stripe &amp; non-Stripe), refund to wallet, amount validation, webhook refund processing.</li><li><strong>WalletService</strong>: Credit/debit with pessimistic locking, balance checks, insufficient balance rejection.</li><li><strong>InventoryService</strong>: Reserve, release, deduct with negative stock prevention.</li><li><strong>CouponService</strong>: Percentage, fixed, free shipping, buy-X-get-Y with real cart item matching.</li></ul><hr><h2 id="running-the-tests" tabindex="-1">Running the Tests <a class="header-anchor" href="#running-the-tests" aria-label="Permalink to &quot;Running the Tests&quot;">​</a></h2><p>To run the test suite locally, use the Artisan command or PHPUnit directly.</p><h3 id="run-all-tests" tabindex="-1">Run all tests <a class="header-anchor" href="#run-all-tests" aria-label="Permalink to &quot;Run all tests&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><h3 id="run-tests-in-parallel-fastest" tabindex="-1">Run tests in parallel (Fastest) <a class="header-anchor" href="#run-tests-in-parallel-fastest" aria-label="Permalink to &quot;Run tests in parallel (Fastest)&quot;">​</a></h3><p>If you have a multi-core machine, you can run tests in parallel to cut execution time down to seconds:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parallel</span></span></code></pre></div><h3 id="run-a-specific-test-class" tabindex="-1">Run a specific test class <a class="header-anchor" href="#run-a-specific-test-class" aria-label="Permalink to &quot;Run a specific test class&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/Feature/Api/Cart/CartTest.php</span></span></code></pre></div><h3 id="run-tests-with-a-specific-keyword" tabindex="-1">Run tests with a specific keyword <a class="header-anchor" href="#run-tests-with-a-specific-keyword" aria-label="Permalink to &quot;Run tests with a specific keyword&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter=AdminProductTest</span></span></code></pre></div><hr><h2 id="mocking-external-services" tabindex="-1">Mocking External Services <a class="header-anchor" href="#mocking-external-services" aria-label="Permalink to &quot;Mocking External Services&quot;">​</a></h2><p>To prevent tests from making actual external network requests (which would be slow and brittle), LaraCommerce heavily utilizes mocking:</p><ul><li><strong>Stripe</strong>: The Stripe API client is mocked during checkout tests to simulate successful and failed charges.</li><li><strong>Webhook Events</strong>: Stripe webhook handlers are tested by calling <code>processWebhookEvent()</code> directly with synthetic event objects, bypassing <code>Stripe\\Webhook::constructEvent()</code> signature verification. This allows full coverage of deduplication, match dispatching, and all 6 handler branches.</li><li><strong>MinIO/S3</strong>: The <code>Storage::fake(&#39;s3&#39;)</code> facade is used to simulate image uploads without hitting the actual bucket.</li><li><strong>Mail</strong>: <code>Mail::fake()</code> is used to assert that emails (like verification links or invoices) were queued or sent.</li><li><strong>Notifications</strong>: <code>Notification::fake()</code> verifies that push notifications or webhooks were dispatched.</li></ul>`,43)])])}const g=s(n,[["render",r]]);export{u as __pageData,g as default};
